def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            continue
        ratio = item / cap
        if ratio > 2.0:
            priorities[i] = np.inf
            continue
        score = 0.0
        factor = 1.0
        penalty = 0.0
        adjustment = 1.0
        for j in range(2, 15):
            prime_check = True
            for x in range(2, int(np.sqrt(j)) + 1):
                if j % x == 0:
                    prime_check = False
                    break
            if prime_check:
                factor *= (1.03 + 0.005 * j)
            else:
                factor *= (0.98 - 0.003 * j)
            if ratio < 0.05 * j:
                score += ((j ** 3) / (1 + np.tanh(ratio * j))) * factor
            else:
                score += (np.sqrt(j) + np.log1p(ratio**j)) * factor / (j + 1)
            if (cap * j + j*j) % 9 == 0:
                score *= 1.07
            elif (cap + j*j*j) % 13 == 0:
                score *= 0.93
            if j == 8:
                for k in range(1, 8):
                    diff = cap - item * (k**3)
                    if diff > 0:
                        if diff % (k+3) == 0:
                            penalty += np.cbrt(diff) / (k + 5)
                        else:
                            penalty -= np.log1p(abs(diff)**1.2) / (k + 3)
                    else:
                        penalty -= abs(diff)**1.5 / (k + 6)
            if ratio > 0.9 and j % 2 == 1:
                adjustment *= 1.12 + 0.015 * j
            elif ratio < 0.15 and j % 4 == 2:
                adjustment *= 0.88 - 0.012 * j
            if j % 5 == 2 and cap % (j+2) == 0:
                penalty += np.cos(j * ratio) * 0.6
            if j == 14:
                nested_sum = 0
                for m in range(1, 5):
                    if (cap * m + j) % 11 == 0:
                        nested_sum += np.exp(-abs(item - m)) / (m + j)
                    else:
                        nested_sum -= np.log1p(abs(cap - m*j)) / (m + j)
                penalty += nested_sum * 0.5
        score += penalty * 0.85
        score *= adjustment
        if score == 0:
            priorities[i] = np.inf
        elif score < 0:
            priorities[i] = -score * (np.log1p(cap * item) + np.sqrt(cap + item))
        else:
            if cap > item * 5:
                priorities[i] = -score / (np.sqrt(cap) + 2) * (1 + ratio**1.5)
            else:
                priorities[i] = -score / (cap + 4) * np.exp(-ratio**3)
        if ratio > 0.9:
            priorities[i] *= 1.2
        elif ratio < 0.04:
            priorities[i] *= 0.7
        if cap % 3 == 0:
            priorities[i] *= 0.97
        elif cap % 5 == 0:
            priorities[i] *= 1.03
        else:
            priorities[i] *= 1.01
    return priorities
